INSERT INTO `candidateanswers` VALUES (1,1,6,'Explain the difference between `display: none;` and `visibility: hidden;` in HTML. What are the implications for layout and accessibility?','display: none;` removes the element entirely from the document flow, causing other elements to reflow to fill its space. Screen readers will not announce it. `visibility: hidden;` hides the element visually but it still occupies space in the layout, so other elements remain in their original positions. Screen readers might still announce it (depending on implementation). Therefore, `visibility: hidden` is generally preferred when you want to hide something temporarily without affecting the layout or accessibility dramatically if screen readers are appropriately configured to ignore it.\"},{\"question\":\"Describe the purpose of the `<picture>` element. When would you use it over a standard `<img>` tag, and what are the benefits?','2025-06-10 05:56:00','2025-06-10 05:56:00'),(2,1,6,'Describe the purpose of the `<picture>` element. When would you use it over a standard `<img>` tag, and what are the benefits?','jhdfjs','2025-06-10 05:56:00','2025-06-10 05:56:00'),(3,1,6,'What are data attributes (e.g., `data-*`) in HTML, and how can they be used effectively? Provide an example.','\"Data attributes are custom attributes prefixed with `data-` that allow you to store extra information directly within an HTML element. They can be accessed and manipulated using JavaScript. They are effective for storing data that is specific to an element and needed by JavaScript logic without polluting the DOM with non-standard attributes or relying on external data structures. Example: `<div id=\'myElement\' data-user-id=\'123\' data-username=\'JohnDoe\'>...</div>`.  In JavaScript: `const userId = document.getElementById(\'myElement\').dataset.userId;`\"},{\"question\":\"Explain the concept of semantic HTML. ','2025-06-10 05:56:00','2025-06-10 05:56:00'),(4,1,6,'Explain the concept of semantic HTML. Provide examples of semantic HTML elements and discuss why using them is important.','fdsd','2025-06-10 05:56:00','2025-06-10 05:56:00'),(5,1,6,'Discuss the advantages and disadvantages of using inline styles, internal styles, and external stylesheets. When would you choose one over the others?','sd','2025-06-10 05:56:00','2025-06-10 05:56:00'),(6,2,8,'What is Object-Oriented Programming',',mnfndfjd','2025-06-10 08:42:07','2025-06-10 08:42:07'),(7,2,8,'what is java ?',',fjehfejr','2025-06-10 08:42:07','2025-06-10 08:42:07'),(8,2,6,'What is Object-Oriented Programming','OOPS stands for Object-Oriented Programming System. It\'s a programming paradigm that structures software design around objects, which are collections of data and functions that represent real-world entities','2025-06-11 04:07:04','2025-06-11 04:07:04'),(9,2,6,'what is java ?','DS','2025-06-11 04:07:04','2025-06-11 04:07:04');
/*!40000 ALTER TABLE `candidateanswers` ENABLE KEYS */;
UNLOCK TABLES;

